UPDATE CURRICULUM
SET USE_YN = 'N', LAST_MDFR_ID = #{lastMdfrId}, MDFCN_DT = SYSDATE
WHERE CURRICULUM_ID = #{curriculumId}

UPDATE COURSE
SET CURRICULUM_ID = #{curriculumId}, SORT_ORD = #{sortOrd}
WHERE COURSE_SN = #{courseSn}

UPDATE COURSE
SET CURRICULUM_ID = NULL, SORT_ORD = NULL
WHERE COURSE_SN = #{courseSn}
